module RefModule(clk, hardreset, reset);input clk, hardreset; 
 output reset; 
 reg [3:0] obf_reset_reg, next_reset_reg; 
 assign reset = obf_reset_reg[3]; 
 initial obf_reset_reg = 4'hF; 
 always @ (posedge clk or posedge hardreset) 
 begin 
  if (hardreset) 
  obf_reset_reg = 4'hF; 
  else obf_reset_reg = next_reset_reg; 
 end 
 always @* 
 begin 
  next_reset_reg = {obf_reset_reg,1'b0}; 
 end 
 endmodule
